(async () => {
  const username = '${{ args.username }}';
  let attempts = 0;

  while (attempts < 20) {
    const followBtn = document.querySelector('[data-testid$="-follow"]');
    if (followBtn) return [{ status: 'success', message: 'Not following @' + username }];

    const unfollowBtn = document.querySelector('[data-testid$="-unfollow"]');
    if (unfollowBtn) {
      unfollowBtn.click();
      await new Promise(r => setTimeout(r, 1000));

      const confirmBtn = document.querySelector('[data-testid="confirmationSheetConfirm"]');
      if (confirmBtn) {
        confirmBtn.click();
        await new Promise(r => setTimeout(r, 1000));
      }

      const verify = document.querySelector('[data-testid$="-follow"]');
      if (verify) return [{ status: 'success', message: 'Successfully unfollowed @' + username }];
      return [{ status: 'failed', message: 'Unfollow action initiated but UI did not update' }];
    }

    await new Promise(r => setTimeout(r, 500));
    attempts++;
  }

  return [{ status: 'failed', message: 'Could not find Unfollow button' }];
})()
